def set_span_status(span: trace.Span, exc: Exception | None = None) -> None:
    """Mark a span OK or ERROR and record exceptions."""
    if exc is None:
        span.set_status(Status(StatusCode.OK))
    else:
        span.set_status(Status(StatusCode.ERROR, description=str(exc)[:1000]))
        span.record_exception(exc)


