_failure_count: int = 0
_failure_until: float = 0.0


class CircuitOpenError(RuntimeError):
    """Raised when the circuit breaker is open and Honcho calls are skipped."""


def circuit_allows() -> bool:
    """Return False when the circuit breaker is open (Honcho is likely down)."""
    return _time.monotonic() >= _failure_until


# Circuit breaker constants. Kept here rather than in Filter Valves so that
# all three plugins (filter, tools, actions) share the same behaviour — they
# all feed the same module-level counter.
_CIRCUIT_BREAKER_THRESHOLD = 3
_CIRCUIT_BREAKER_COOLDOWN = 60.0


def record_result(success: bool) -> None:
    """Update the circuit breaker with the result of a Honcho API call."""
    global _failure_count, _failure_until
    if success:
        _failure_count = 0
        _failure_until = 0.0
    else:
        _failure_count += 1
        if _failure_count >= _CIRCUIT_BREAKER_THRESHOLD:
            _failure_until = _time.monotonic() + _CIRCUIT_BREAKER_COOLDOWN


