    async def search_messages(
        self,
        user_id: str,
        model_id: str,
        chat_id: str,
        query: str,
        *,
        sender: Literal["user", "assistant", "all"] = "all",
        created_after: str | None = None,
        created_before: str | None = None,
        metadata: dict[str, Any] | None = None,
        limit: int = 10,
    ) -> list[Any]:
        """Search messages across sessions, optionally filtered by sender, date, and metadata."""
        start = _time.monotonic()
        with get_tracer().start_as_current_span("honcho.search_messages") as span:
            span.set_attribute("honcho.sender", sender)
            span.set_attribute("honcho.query_length", len(query))
            _success = True
            try:
                filters: dict[str, Any] = {}

                if created_after or created_before:
                    created_at: dict[str, str] = {}
                    if created_after:
                        created_at["gte"] = created_after
                    if created_before:
                        created_at["lte"] = created_before
                    filters["created_at"] = created_at

                if metadata:
                    filters["metadata"] = metadata

                if sender == "user":
                    user_peer, _, _, _ = await self.resources(user_id, model_id, chat_id)
                    results = await user_peer.aio.search(query, filters=filters, limit=limit)
                elif sender == "assistant":
                    _, assistant_peer, _, _ = await self.resources(user_id, model_id, chat_id)
                    results = await assistant_peer.aio.search(query, filters=filters, limit=limit)
                else:
                    # "all" must stay scoped to the current user and model peers;
                    # the workspace-level search would include other users.
                    user_peer, assistant_peer, _, _ = await self.resources(
                        user_id, model_id, chat_id
                    )
                    seen: set[str] = set()
                    merged: list[Any] = []
                    for peer in (user_peer, assistant_peer):
                        for message in await peer.aio.search(query, filters=filters, limit=limit):
                            message_id = getattr(message, "id", None)
                            if message_id is None:
                                merged.append(message)
                            elif message_id not in seen:
                                seen.add(message_id)
                                merged.append(message)

                    # Sort by created_at descending so the most recent messages
                    # appear first.  Messages without a timestamp sort last.
                    def _sort_key(m: Any) -> Any:
                        ts = getattr(m, "created_at", None)
                        if ts is None:
                            return ()
                        try:
                            return (ts,)
                        except Exception:
                            return ()

                    merged.sort(key=_sort_key, reverse=True)
                    results = merged
                span.set_attribute("honcho.result_count", len(results))
                set_span_status(span)
                return results[:limit]
            except Exception as exc:
                _success = False
                set_span_status(span, exc)
                raise
            finally:
                record_metric(
                    "operation_duration",
                    _time.monotonic() - start,
                    self._telemetry_attributes("search_messages"),
                )
                record_metric(
                    "requests_total",
                    1,
                    {
                        **self._telemetry_attributes("search_messages"),
                        "result": "success" if _success else "error",
                    },
                )

